Para seguir con la implementaciГіn del backend del sistema de puntos de venta (POS) para un kiosco, necesitamos crear los archivos principales. Este backend se basarГЎ en Node.js y Express.js, utilizando MongoDB como base de datos.

### Archivo: models.py

Este archivo definirГЎ las modelos de datos que utilizaremos con MongoDB.

```python
import os
from flask_pymongo import PyMongo
from dotenv import load_dotenv

load_dotenv()

MONGO_URI = os.getenv('MONGO_URI')

mongo = PyMongo(app, uri=MONGO_URI)

class InventoryModel:
    def __init__(self):
        self.collection = mongo.db.inventory

    def get_inventory(self):
        return self.collection.find_one({}, {"_id": 0})

    def update_inventory(self, data):
        result = self.collection.update_one(
            {},
            {
                "$set": data
            }
        )
        return result.modified_count > 0


class TransactionsModel:
    def __init__(self):
        self.collection = mongo.db.transactions

    def create_transaction(self, transaction_data):
        new_transaction_id = str(len(list(self.collection.find())))
        transaction_data['transaction_id'] = new_transaction_id
        return self.collection.insert_one(transaction_data).inserted_id


class ReportsModel:
    def __init__(self):
        self.collection = mongo.db.reports

    def generate_report(self, data):
        self.collection.insert_one(data)
```

### Archivo: routes.py

Este archivo definirГЎ las rutas HTTP que manejarГЎn las peticiones del frontend.

```python
from flask import Flask, request, jsonify
from models import InventoryModel, TransactionsModel, ReportsModel
import os

app = Flask(__name__)
app.config['MONGO_URI'] = os.getenv('MONGO_URI')

# Inicializar MongoDB con PyMongo
mongo = PyMongo(app)

@app.route('/inventory', methods=['GET'])
def get_inventory():
    inventory_model = InventoryModel()
    return jsonify(inventory_model.get_inventory())

@app.route('/transactions', methods=['POST'])
def create_transaction():
    transaction_data = request.json
    transactions_model = TransactionsModel()
    new_id = transactions_model.create_transaction(transaction_data)
    return jsonify({"message": f"Transaction created with ID: {new_id}"}), 201

@app.route('/reports', methods=['POST'])
def generate_report():
    report_data = request.json
    reports_model = ReportsModel()
    reports_model.generate_report(report_data)
    return jsonify({"message": "Report generated successfully"}), 201


if __name__ == '__main__':
    app.run(debug=False, port=5000)
```

