  const jwt = require('jsonwebtoken');

  function authMiddleware(req, res, next) {
      const token = req.header('x-auth-token');
      if (!token) return res.status(401).json({ message: 'No hay token en la cabecera' });

      try {
          const decoded = jwt.verify(token, 'clave_secreta');
          req.user = decoded;
          next();
      } catch (error) {
          res.status(403).json({ message: 'Token no vГЎlido' });
